class Solution:
    def splitIntoFibonacci(self, num):
        """
        :type num: str
        :rtype: List[int]
        """
        def backtrack(index, path):
            if index == len(num):
                return len(path) >= 3

            for i in range(index + 1, len(num) + 1):
                # No leading zeros
                if num[index] == '0' and i > index + 1:
                    break

                current = int(num[index:i])

                # Check 32-bit limit
                if current > 2**31 - 1:
                    break

                if len(path) < 2:
                    path.append(current)
                    if backtrack(i, path):
                        return True
                    path.pop()
                else:
                    if current == path[-1] + path[-2]:
                        path.append(current)
                        if backtrack(i, path):
                            return True
                        path.pop()
                    elif current > path[-1] + path[-2]:
                        break

            return False

        path = []
        backtrack(0, path)
        return path
